oxy_webhelp_navlinks = {"data_sources-d27243e3549":{"topics":[{"title":"Rubrik Backup Service","shortdesc":"<p class=\"shortdesc\">The Rubrik Backup Service provides integration with protected resources and host         systems and coordinates activities between the Rubrik cluster and the host.<\/p>","href":"rbs\/rubrik_backup_service.html","attributes":{"data-id":"rubrik_backup_service"},"menu":{"hasChildren":false},"tocID":"rubrik_backup_service-d27243e3560","next":"rubrik_backup_service-d27243e3560"},{"title":"SMB security","shortdesc":"<p class=\"shortdesc\">With the SMB security feature in <span class=\"ph\">RSC<\/span>, a Rubrik cluster provides         security for SMB shares by requiring Active Directory authentication and enforcing SMB         security.<\/p>","href":"saas\/rsc_smb_security.html","attributes":{"data-id":"rsc_smb_security"},"menu":{"hasChildren":false},"tocID":"rsc_smb_security-d27243e3947","next":"rsc_smb_security-d27243e3947"},{"title":"Guest OS credentials","shortdesc":"<p class=\"shortdesc\">Guest OS credentials are the username and password that a Rubrik cluster uses to         provide access to the guest operating system and files of a vSphere virtual machine. When         Rubrik Backup Service is not installed or disconnected, you can use guest OS credentials to         recover virtual machine files.<\/p>","href":"cdm_old\/guest_os_credentials.html","attributes":{"data-id":"guest_os_credentials"},"menu":{"hasChildren":false},"tocID":"guest_os_credentials-d27243e4030","next":"guest_os_credentials-d27243e4030"}]}};